parameters.jsCode:
// Validate x-api-key header
const apiKey = $input.item.json.headers['x-api-key'];
const expectedKey = $env.ESTIMATOR_API_KEY;

if (!apiKey || apiKey !== expectedKey) {
  throw new Error('UNAUTHORIZED');
}

const body = $input.item.json.body;

// Validate required fields
if (!body.action || body.action !== 'push_estimate') {
  throw new Error('Invalid action');
}

if (!body.jtPayload || !Array.isArray(body.jtPayload) || body.jtPayload.length === 0) {
  throw new Error('jtPayload is required and must be a non-empty array');
}

// Determine job mode
const isNewJob = body.mode === 'new_job';

if (isNewJob) {
  if (!body.newJob || !body.newJob.customerId) {
    throw new Error('newJob.customerId is required for new jobs');
  }
} else {
  if (!body.jobId) {
    throw new Error('jobId is required for existing jobs');
  }
}

return {
  json: {
    // Job identification
    mode: body.mode || 'existing',
    jobId: body.jobId || null,
    jobNumber: body.jobNumber || null,
    jobName: body.jobName || null,
    customerId: body.customerId || body.newJob?.customerId || null,
    customerName: body.customerName || body.newJob?.customerName || null,
    projectType: body.projectType || 'general',

    // For new job creation
    newJob: body.newJob || null,

    // Payload data
    projectState: body.projectState || {},
    jtPayload: body.jtPayload,
    totals: body.totals || {},

    // Metadata
    timestamp: body.timestamp || new Date().toISOString(),
    requestId: `est-${Date.now()}-${Math.random().toString(36).substr(2, 6)}`
  }
};

// Extract created job details from Pave response
const response = $input.item.json;
const prevData = $('Validate Request').item.json;

if (response.errors && response.errors.length > 0) {
  throw new Error(`JT job creation failed: ${response.errors[0].message}`);
}

const createdJob = response.createJob;

if (!createdJob || !createdJob.id) {
  throw new Error('JT job creation returned no job ID');
}

return {
  json: {
    ...prevData,
    jobId: createdJob.id,
    jobNumber: createdJob.number,
    jobName: createdJob.name,
    jobCreated: true
  }
};

// Pass through existing job data
return {
  json: {
    ...$json,
    jobCreated: false
  }
};

// Parse JT push result and determine success
const response = $input.item.json;
const prevData = $('Merge Job Data').item.json;

let jtPushSuccess = false;
let jtPushError = null;
let jtPushResult = null;

if (response.errors && response.errors.length > 0) {
  jtPushError = response.errors.map(e => e.message).join('; ');
} else if (response.addBudgetLineItems) {
  jtPushSuccess = true;
  jtPushResult = response.addBudgetLineItems;
} else if (response.error) {
  // HTTP-level error
  jtPushError = response.error.message || 'HTTP request failed';
} else {
  jtPushError = 'Unknown JT response format';
}

return {
  json: {
    ...prevData,
    jtPushSuccess,
    jtPushError,
    jtPushResult,
    itemsPushed: jtPushSuccess ? prevData.jtPayload.length : 0
  }
};

